        [Fact()]
        [TestBeforeAfter]
        public void BM25_Experiment()
        {
            var corpus = new AIMemorys
            {
                new AIMemory { Text = File.ReadAllText(@"C:\DVT\fAI\src\fAI.Tests\TestFiles\Dr Henry Jekyll - Character Profile.md") },
                new AIMemory{ Text = File.ReadAllText(@"C:\DVT\fAI\src\fAI.Tests\TestFiles\JANE DOE, Back Issues.md") },
            };

            var bm25 = new Bm25(corpus);
            bm25.GetScores("doctor england", corpus);
            Assert.True(corpus[0].Score > corpus[1].Score, "Doc containing 'cat' should outscore doc without it.");
        }

        [Fact()]
        [TestBeforeAfter]
        public void Basic_BM25()
        {
            var corpus = new AIMemorys
            {
                new AIMemory { Text = "the cat sat on the mat" },   // doc 0 – contains 'cat'
                new AIMemory{ Text = "the dog sat on the log" },   // doc 1 – no 'cat'
            };

            var bm25 = new Bm25(corpus);
            bm25.GetScores("cat on mat", corpus);
            Assert.True(corpus[0].Score > corpus[1].Score, "Doc containing 'cat' should outscore doc without it.");
        }

        const string outputFileName = @"c:\temp\fAI.log";
        void TraceBm25Score(string r) => File.AppendAllText(outputFileName, r + Environment.NewLine);

        private void Trace(string text)
        {
            var lines = text.SplitByCRLF();
            foreach (var s in lines)
                HttpBase.Trace(s, this);
        }

