        /// <summary>
        /// //////////////[Fact()]
        /// </summary>
        [TestBeforeAfter]
        public void CreateCrossReferenceTables_Sync()
        {
            var aiManager = new AIMemoryManager(TEST_DB);
            //var aiManager = new AIMemoryManager(@"C:\Users\ftorres\AppData\Roaming\WinSpeak\WinSpeak.AIMemory.db");
            var CRTManager = new AIMemoryCrossReferenceTableManager(aiManager);
            CRTManager.Sync();

            var sbReport = new StringBuilder();
            sbReport.AppendLine("# Cross Reference Table Report - WinSpeak.AIMemory.test.1.db").AppendLine();

            var markdownRootFolder = @"c:\users\ftorres\dropbox\markdown";
            var peopleCRT = CRTManager.Get("people");
            Assert.True(peopleCRT.Entries.Count > 0);
            var peopleCRTReport = aiManager.GenerateReportCrossReferenceTable(peopleCRT, markdownRootFolder);
            sbReport.AppendLine(peopleCRTReport);

            var locationsCRT = CRTManager.Get("locations");
            Assert.True(locationsCRT.Entries.Count > 0);
            var locationsCRTReport = aiManager.GenerateReportCrossReferenceTable(locationsCRT, markdownRootFolder);
            sbReport.AppendLine(locationsCRTReport);

            var topicsCRT = CRTManager.Get("topics");
            Assert.True(topicsCRT.Entries.Count > 0);
            var topicsCRTReport = aiManager.GenerateReportCrossReferenceTable(topicsCRT, markdownRootFolder);
            sbReport.AppendLine(topicsCRTReport);

            var fileReportMd = @"C:\Users\ftorres\Dropbox\MARKDOWN\CrossReferenceTables.Report.md";
            File.Delete(fileReportMd);
            File.WriteAllText(fileReportMd, sbReport.ToString());
        }

        [Fact()]
        [TestBeforeAfter]
