        {
            var records = EmbeddingCommonRecord.FromJsonFile(@"C:\DVT\fAI\src\fAI.Beetles.All\Beatles.All.json");
            var aiManager = new AIMemoryManager(BeatlesTestDBName);
            aiManager.__simulate_metadata_computation__ = true;
