        [Fact()]
        [TestBeforeAfter]
        public void ToJson()
        {
            var aiManager = new AIMemoryManager(TestDBName);
            aiManager.__simulate_embedding_computation__ = true;

            for (var i = 0; i < 4; i++)
            {
                if (i % 2 == 0)
                {
                    var aiMemory2 = new AIMemory()
                    {
                        PublishedUrl = $"https://www.example.com/article{i}",
                        Title = $"Example Article {i}",
                        Text = DefaultMarkdownText + $" {i}",
                        Type = PublishedDocumentInfoType.MarkdownFile,
                        LocalFile = $"C:\\temp\\article{i}.md",
                    };
                    Assert.True(aiMemory2.IsMarkDownFile());
                    aiManager.Add(aiMemory2);
                }
                else
                {
                    var aiMemory = new AIMemory()
                    {
                        PublishedUrl = $"https://www.example.com/article{i}",
                        Title = $"Example Article {i}",
                        Text = DefaultMarkdownText + $" {i}",
                        Type = PublishedDocumentInfoType.UserAINote,
                        LocalFile = null,
                    };
                    aiManager.Add(aiMemory);
                }
            }

            var jsonFile = aiManager.ToJsonFile();

            aiManager.AddFile("jsonFile", jsonFile);
            var newJsonFile = aiManager.GetFile("jsonFile", jsonFile + "2");

            Assert.Equal(new FileInfo(jsonFile).Length, new FileInfo(newJsonFile).Length);
        }

        const string DefaultMarkdownText = "This is the text of the example article. created March 31 2026, in Boston, MA, USA By Richard Harrison. Richard Harrison created an important note about Windows user and Productivity";

        [Fact()]
        [TestBeforeAfter]
        public void Add_Update_Markdown_Search_Delete()
        {
            var aiManager = new AIMemoryManager(TestDBName);
            aiManager.__simulate_embedding_computation__ = true;
            aiManager.__simulate_metadata_computation__ = true;

            var aiMemory = new AIMemory()
            {
                PublishedUrl = $"https://www.example.com/article",
                Title = $"Example Article",
                Text = DefaultMarkdownText,
                Type = PublishedDocumentInfoType.MarkdownFile,
                LocalFile = $"C:\\temp\\article.md",
            };

            aiManager.Add(aiMemory, Environment.GetEnvironmentVariable("OPENAI_API_KEY"));

            var __id__ = aiMemory.Id;
            var __mid__ = aiMemory.MID;
            Assert.Equal(__mid__.ToString(), __id__.ToString());

            VerifyAIMemoryInDB(aiManager, aiMemory);

            aiMemory.PublishedUrl += " - Updated";
            aiMemory.Title += " - Updated";
            aiMemory.Text += " - Updated";

            var (succeeded, usage, id) = aiManager.AddUpdate(aiMemory, aiMemory.LocalFile,
                openAiKey: null,//Environment.GetEnvironmentVariable("OPENAI_API_KEY"),
                llmApiKey: null//"BAD-KEY"
            );
            Assert.True(usage.InputTokens > 0);
            Assert.True(usage.OutputTokens > 0);
            Assert.True(usage.TotalTokens > 0);

            var aiMemoryReloaded = aiManager.GetFromId(id);
            Assert.Equal(aiMemory.Title, aiMemoryReloaded.Title);

            VerifyAIMemoryInDB(aiManager, aiMemory);

            aiManager.Delete(aiMemory);
            aiMemory = aiManager.GetFromId(aiMemory.Id);
            Assert.Null(aiMemory);
        }

        [Fact()]
        [TestBeforeAfter]
        public void Add_Update_Markdown_Search_Delete_Image()
        {
            var aiManager = new AIMemoryManager(TestDBName);
            //aiManager.__simulate_embedding_computation__ = true;
            //aiManager.__simulate_metadata_computation__ = true;

            var imageFileName = base.GetTestFile("ManAndBoartInStorm.png");
            var aiMemory = new AIMemory()
            {
                Title = $"one big image",
                Text = testIMageDescription,
                Type = PublishedDocumentInfoType.ImageFile,
                LocalFile = imageFileName,
            };

            aiManager.Add(aiMemory,
                openAiKey: Environment.GetEnvironmentVariable("OPENAI_API_KEY"),
                llmApiKey: Environment.GetEnvironmentVariable("GOOGLE_GENERATIVE_AI_API_KEY")
                );
            AssertAIMemoryExportToMedia(aiMemory);

            var __id__ = aiMemory.Id;
            var __mid__ = aiMemory.MID;

            VerifyAIMemoryInDB(aiManager, aiMemory);

            aiMemory.PublishedUrl += " - Updated";
            aiMemory.Title += " - Updated";
            aiMemory.Text += " - Updated";

            var (succeeded, usage, id) = aiManager.AddUpdate(aiMemory, aiMemory.LocalFile,
                openAiKey: Environment.GetEnvironmentVariable("OPENAI_API_KEY"),
                llmApiKey: Environment.GetEnvironmentVariable("GOOGLE_GENERATIVE_AI_API_KEY"),
                clearEmbeddings: true);
            Assert.True(usage.InputTokens > 0);
            Assert.True(usage.OutputTokens > 0);
            Assert.True(usage.TotalTokens > 0);

            var json = aiMemory.ToJSON();

            VerifyAIMemoryInDB(aiManager, aiMemory);

            AssertAIMemoryExportToMedia(aiMemory);

            aiManager.Delete(aiMemory);
            AssertAIMemoryIsDeleted(aiManager, aiMemory);
        }

        private static void AssertAIMemoryIsDeleted(AIMemoryManager aiManager, AIMemory aiMemory)
        {
            aiMemory = aiManager.GetFromId(aiMemory.Id);
            Assert.Null(aiMemory);
        }

        private static string AssertAIMemoryExportToMedia(AIMemory aiMemory)
        {
            var pngFileName = aiMemory.ExportMedia();
            Assert.True(File.Exists(pngFileName));
            File.Delete(pngFileName);
            return pngFileName;
        }

        [Fact()]
        [TestBeforeAfter]
        public void Add_Update_Search_Delete()
        {
            var aiManager = new AIMemoryManager(TestDBName);
            aiManager.__simulate_embedding_computation__ = true;

            var aiMemory = new AIMemory()
            {
                PublishedUrl = "https://www.example.com/article1",
                Title = "Example Article 1",
                Text = DefaultMarkdownText,
                Type = PublishedDocumentInfoType.UserAINote,
                LocalFile = null,
            };

            var (usage, newId) = aiManager.Add(aiMemory, Environment.GetEnvironmentVariable("OPENAI_API_KEY"));
            Assert.True(usage.InputTokens > 0);
            Assert.True(usage.OutputTokens > 0);
            Assert.True(usage.TotalTokens > 0);

            var aiMemoryReLoaded = aiManager.GetFromId(newId);
            Assert.Equal(aiMemory.Title, aiMemoryReLoaded.Title);

            var __id__ = aiMemory.Id;

            VerifyAIMemoryInDB(aiManager, aiMemory);

            aiMemory.PublishedUrl += " - Updated";
            aiMemory.Title += " - Updated";
            aiMemory.Text += " - Updated";
            var (succeeded, usageUpdate) = aiManager.ComputeEmbeddingsAndMetaData(aiMemory);
            Assert.True(succeeded);
            Assert.True(usageUpdate.OutputTokens > 0);
            Assert.True(usageUpdate.InputTokens > 0);
            Assert.True(usageUpdate.TotalTokens > 0);

            aiManager.Update(aiMemory);

            VerifyAIMemoryInDB(aiManager, aiMemory);

            aiManager.Delete(aiMemory);
            aiMemory = aiManager.GetFromId(aiMemory.Id);
            Assert.Null(aiMemory);
        }

        private static void VerifyAIMemoryInDB(AIMemoryManager aiMI, AIMemory aiMemory)
        {
            var aiMemory2 = aiMI.GetFromId(aiMemory.Id);
            Assert.NotNull(aiMemory2);
            Assert.Equal(aiMemory.PublishedUrl?.Trim(), aiMemory2.PublishedUrl?.Trim());
            Assert.Equal(aiMemory.Title, aiMemory2.Title);
            Assert.Equal(aiMemory.Text.Trim(), aiMemory2.Text.Trim());
            Assert.Equal(aiMemory.Type, aiMemory2.Type);
            Assert.Equal(aiMemory.LocalFile, aiMemory2.LocalFile);
            Assert.True(aiMemory2.AIMetaData.MetaData.Count > 0);
            AssertFloatArrayEqual(aiMemory.Embeddings.ToArray(), aiMemory2.Embeddings.ToArray(), 0);
        }

        public static void AssertFloatArrayEqual(float[] expected, float[] actual, float tolerance = 1e-5f)
        {
            Assert.Equal(expected.Length, actual.Length);
            for (int i = 0; i < expected.Length; i++)
                Assert.True(Math.Abs(expected[i] - actual[i]) <= tolerance, $"Index {i}: expected {expected[i]} but got {actual[i]} (tolerance {tolerance})");
        }

